mapper.select:
SELECT emp.emp_name, dep.dep_name, att.work_date AS workDate, att.work_days AS workDays, att.work_hours AS workHours FROM ATTENDANCE att JOIN EMPLOYEE emp ON att.emp_id = emp.emp_id JOIN DEPARTMENT dep ON emp.dep_id = dep.dep_id
AND emp.emp_id = #{empId}
AND att.work_date >= #{startDate}
AND att.work_date <= #{endDate}

